// Node: "Filter_Valid_Users"

// Filter active users with valid subscriptions
const allUsers = $input.all();
const now = Date.now();

const validUsers = allUsers.filter(item => {
  const user = item.json;

  // Must be active
  if (!user.is_active) return false;

  // Must have subscription ID
  if (!user.subscription_id) return false;

  // Must have access token
  if (!user.access_token) return false;

  // Must have subscription expiry date
  if (!user.subscription_expires_at) return false;

  return true;
});

if (validUsers.length === 0) {
  console.log('No users to process - stopping workflow');
  return [];
}

return validUsers;

// ═══════════════════════════════════════════════════════════
// COMPREHENSIVE TOKEN & SUBSCRIPTION EXPIRY CHECK
// ═══════════════════════════════════════════════════════════

const user = $input.item.json;
const now = Date.now();

console.log(`\n┌─────────────────────────────────────────┐`);
console.log(`│ Processing: ${user.user_email.padEnd(28)} │`);
console.log(`└─────────────────────────────────────────┘`);

// ═══════════════════════════════════════
// 1. TOKEN EXPIRY CHECK
// ═══════════════════════════════════════
let needsTokenRefresh = false;
let tokenStatus = 'unknown';

if (!user.token_expires_at_unix) {
  needsTokenRefresh = true;
  tokenStatus = 'missing_expiry';
} else {
  // FIX: Don't multiply by 1000 if already in milliseconds
  let tokenExpiresAt = parseInt(user.token_expires_at_unix);

  // Check if value is in seconds (< year 2100 in seconds)
  if (tokenExpiresAt < 4102444800) {
    tokenExpiresAt = tokenExpiresAt * 1000;
  }

  const tokenExpiresIn = tokenExpiresAt - now;
  const tokenHoursRemaining = tokenExpiresIn / (1000 * 60 * 60);

  // Refresh if expires in < 5 minutes
  const fiveMinutes = 5 * 60 * 1000;
  needsTokenRefresh = tokenExpiresIn < fiveMinutes;

  tokenStatus = needsTokenRefresh ? 'needs_refresh' : 'valid';

  console.log(`Token: ${tokenStatus}`);
  console.log(`Expires: ${new Date(tokenExpiresAt).toISOString()}`);
  console.log(`Time remaining: ${tokenHoursRemaining.toFixed(1)}h`);
}

// ═══════════════════════════════════════
// 2. SUBSCRIPTION EXPIRY CHECK
// ═══════════════════════════════════════
let subscriptionStatus = 'unknown';
let renewalAction = 'skip';
let hoursUntilExpiration = 0;

if (!user.subscription_expires_at) {
  subscriptionStatus = 'missing_expiry';
  renewalAction = 'skip';
} else {
  const subExpiresAt = new Date(user.subscription_expires_at).getTime();
  const timeUntilExpiration = subExpiresAt - now;
  hoursUntilExpiration = timeUntilExpiration / (1000 * 60 * 60);

  // ═══════════════════════════════════════
  // DECISION MATRIX (FIXED)
  // ═══════════════════════════════════════

  if (hoursUntilExpiration <= 0) {
    // EXPIRED - Must recreate
    subscriptionStatus = 'expired';
    renewalAction = 'recreate';

  } else if (hoursUntilExpiration < 24) {
    // DANGER ZONE (<24h) - Microsoft blocks renewal
    subscriptionStatus = 'danger_zone';
    renewalAction = 'recreate';

  } else if (hoursUntilExpiration >= 24 && hoursUntilExpiration <= 60) {
    // OPTIMAL RENEWAL WINDOW (24-60h)
    subscriptionStatus = 'renewal_window';
    renewalAction = 'renew';
    console.log(`Subscription: RENEWAL WINDOW - safe to renew`);

  } else {
    // TOO EARLY (>60h)
    subscriptionStatus = 'valid';
    renewalAction = 'skip';
    console.log(`Subscription: Still valid - no action needed`);
  }

  console.log(`Subscription status: ${subscriptionStatus}`);
  console.log(`Expires: ${new Date(subExpiresAt).toISOString()}`);
  console.log(`Time remaining: ${hoursUntilExpiration.toFixed(1)}h`);
  console.log(`Action: ${renewalAction.toUpperCase()}`);
}

return {
  json: {
    ...user,
    // Token info
    needs_token_refresh: needsTokenRefresh,
    token_status: tokenStatus,

    // Subscription info
    subscription_status: subscriptionStatus,
    renewal_action: renewalAction,
    hours_until_expiration: hoursUntilExpiration.toFixed(1),

    // Metadata
    checked_at: new Date().toISOString()
  }
};

const originalUser = $('Analyze_User_Status').item.json;
const tokenResponse = $input.item.json;

console.log(`✅ Token refreshed successfully`);

return {
  json: {
    ...originalUser,
    access_token: tokenResponse.access_token,
    refresh_token: tokenResponse.refresh_token || originalUser.refresh_token,
    token_refreshed: true
  }
};

const originalUser = $('Analyze_User_Status').item.json;

console.error(`❌ Token refresh FAILED - user will be deactivated`);

return {
  json: {
    ...originalUser,
    token_refresh_failed: true,
    should_deactivate: true
  }
};

const user = $input.item.json;

console.log(`⏭️ SKIP - No renewal needed`);
console.log(`   Subscription valid for ${user.hours_until_expiration}h\n`);

return {
  json: {
    user_email: user.user_email,
    action: 'skipped',
    reason: `Subscription valid for ${user.hours_until_expiration}h`,
    success: true
  }
};

const user = $input.item.json;

// Calculate new expiration (3 days from now)
const newExpiration = new Date(Date.now() + (3 * 24 * 60 * 60 * 1000)).toISOString();

console.log(`🔄 Attempting RENEW via PATCH`);
console.log(`   Current expiry: ${user.subscription_expires_at}`);
console.log(`   New expiry: ${newExpiration}`);

return {
  json: {
    ...user,
    new_expiration: newExpiration
  }
};

const originalUser = $('Prepare_Renewal').item.json;
const renewalResponse = $input.item.json;

console.log(`✅ RENEW SUCCESS via PATCH`);
console.log(`   New expiry: ${renewalResponse.expirationDateTime}\n`);

return {
  json: {
    user_email: originalUser.user_email,
    action: 'renewed',
    method: 'patch',
    new_expiration: renewalResponse.expirationDateTime,
    success: true
  }
};

const originalUser = $('Prepare_Renewal').item.json;
const error = $input.item.json.error || $input.item.json;

if (error.message) {
  console.warn(`   Error: ${error.message}`);
}

return {
  json: {
    ...originalUser,
    renewal_failed: true,
    renewal_action: 'recreate' // Force recreation
  }
};

// Track result for this user
const result = $input.item.json;

return {
  json: {
    user_email: result.user_email,
    action: result.action,
    success: result.success,
    timestamp: new Date().toISOString()
  }
};

// Final summary after all users processed
const allResults = $input.all();

const total = allResults.length;
const successful = allResults.filter(r => r.json.success).length;
const failed = allResults.filter(r => !r.json.success).length;
const skipped = allResults.filter(r => r.json.action === 'skipped').length;
const renewed = allResults.filter(r => r.json.action === 'renewed').length;
const recreated = allResults.filter(r => r.json.action === 'recreated').length;

console.log(`\n╔════════════════════════════════════════════╗`);
console.log(`║  SUBSCRIPTION RENEWAL COMPLETE             ║`);
console.log(`╠════════════════════════════════════════════╣`);
console.log(`║  Total Processed:      ${String(total).padStart(15)}   ║`);
console.log(`║  ────────────────────────────────────────  ║`);
console.log(`║  ✅ Successful:         ${String(successful).padStart(15)}   ║`);
console.log(`║  ❌ Failed:             ${String(failed).padStart(15)}   ║`);
console.log(`║  ────────────────────────────────────────  ║`);
console.log(`║  ⏭️  Skipped (valid):   ${String(skipped).padStart(15)}   ║`);
console.log(`║  🔄 Renewed (PATCH):    ${String(renewed).padStart(15)}   ║`);
console.log(`║  🔄 Recreated (DEL+CR): ${String(recreated).padStart(15)}   ║`);
console.log(`╚════════════════════════════════════════════╝\n`);

if (failed > 0) {
  console.error(`⚠️ ${failed} user(s) failed - check logs above for details\n`);
}

return {
  json: {
    summary: {
      total_processed: total,
      successful: successful,
      failed: failed,
      skipped: skipped,
      renewed: renewed,
      recreated: recreated
    },
    details: allResults.map(r => r.json),
    timestamp: new Date().toISOString()
  }
};

// Filter subscriptions for this user's webhook
const webhookUrl = $vars.Email_Categorization_Webhook_URL;
const userEmail = $('Merge_After_Token').item.json.user_email;
const allSubs = $input.item.json.value || [];
const userId = $('Merge_After_Token').item.json.user_id;
const access_token = $('Merge_After_Token').item.json.access_token;

console.log(`Total subscriptions in account: ${allSubs.length}`);
console.log(`Looking for subscriptions for user: ${userEmail} (ID: ${userId})`);

// Filter: Our webhook + this user
const userSubs = allSubs.filter(sub => {
  const matchesWebhook = sub.notificationUrl === webhookUrl;
  const matchesUser = sub.resource && sub.resource.toLowerCase().includes(userEmail.toLowerCase());
  return matchesWebhook && matchesUser;
});

console.log(`Found ${userSubs.length} subscription(s) for ${userEmail}`);

if (userSubs.length === 0) {
  console.log(`No existing subscriptions - will create new one`);
  return [{ 
    json: { 
      _noSubscriptions: true,
      user_email: userEmail,
      user_id: userId,
      access_token: access_token
    } 
  }];  
}

console.log(`Will delete ${userSubs.length} subscription(s):`);
userSubs.forEach((sub, index) => {
  console.log(`${index + 1}. ID: ${sub.id}`);
  console.log(`Expires: ${sub.expirationDateTime}`);
});

// Return each subscription as a separate item for the loop
return userSubs.map(sub => ({
  json: {
    _noSubscriptions: false,  
    subscription_id: sub.id,
    subscription_resource: sub.resource,
    subscription_expires: sub.expirationDateTime,
    user_email: userEmail,
    user_id: userId,
    access_token: access_token
  }
}));

// Node: "Format_Recreate_Result" (Code Node)
// Position: Between Create_Graph_Subscription1 and Store_Subscription_ID1

const createResponse = $input.item.json;
const originalUser = $('Filter_User_Subscriptions').item.json;

console.log(`📊 Checking subscription creation result...`);

// Check if creation was successful
if (createResponse.error) {
  console.error(`❌ RECREATE FAILED: ${createResponse.error.message || JSON.stringify(createResponse.error)}`);
  return {
    json: {
      ...originalUser,
      recreate_failed: true,
      error_message: createResponse.error.message || 'Failed to create subscription'
    }
  };
}

if (!createResponse.id || !createResponse.expirationDateTime) {
  console.error(`❌ RECREATE FAILED: Invalid response from Microsoft`);
  return {
    json: {
      ...originalUser,
      recreate_failed: true,
      error_message: 'Invalid response - missing subscription ID or expiration'
    }
  };
}

console.log(`✅ RECREATE SUCCESS`);
console.log(`   New subscription ID: ${createResponse.id}`);
console.log(`   New expiry: ${createResponse.expirationDateTime}`);

return {
  json: {
    ...originalUser,
    recreate_success: true,  // ✅ CRITICAL: This is what IF_Recreate_Success checks!
    new_subscription_id: createResponse.id,
    new_subscription_expires_at: createResponse.expirationDateTime,
    id: createResponse.id,  // For the database update
    expirationDateTime: createResponse.expirationDateTime  // For the database update
  }
};

const user = $input.item.json;

console.log(`✅ Database updated successfully\n`);

return {
  json: {
    user_email: user.user_email,
    action: 'recreated',
    success: true,
    new_subscription_id: user.new_subscription_id
  }
};

const user = $input.item.json;

console.error(`❌ RECREATE FAILED\n`);

return {
  json: {
    user_email: user.user_email,
    action: 'failed',
    success: false,
    error: user.error_message || 'Unknown error'
  }
};
